using System;
using System.Collections.Generic;
using System.IO;
using System.Text.Json;
using Sitrep.Core;
using Xunit;

namespace Sitrep.Core.Tests
{
    /// <summary>
    /// Conformance test for the C# semver port against the TS-computed golden
    /// fixtures in <c>mod/golden-fixtures/version.json</c>. The fixture is
    /// generated by running the REAL TS functions in
    /// <c>mod/sitrep-kernel/src/version.ts</c>
    /// (`pnpm --filter @gonogo/sitrep-kernel gen:golden-fixtures`) — this test
    /// never hand-authors expected values, it only asserts the C# port
    /// reproduces them.
    /// </summary>
    public class VersionGoldenFixtureTests
    {
        private static readonly string FixturePath = Path.Combine(
            AppContext.BaseDirectory, "golden-fixtures", "version.json");

        public static IEnumerable<object[]> Vectors()
        {
            var json = File.ReadAllText(FixturePath);
            using var doc = JsonDocument.Parse(json);
            var vectors = new List<object[]>();
            foreach (var element in doc.RootElement.EnumerateArray())
            {
                // Clone: the JsonDocument (and its elements) are invalidated
                // once this method returns and `doc` is disposed.
                vectors.Add(new object[] { element.Clone() });
            }
            return vectors;
        }

        [Theory]
        [MemberData(nameof(Vectors))]
        public void MatchesTsReference(JsonElement vector)
        {
            var fn = vector.GetProperty("fn").GetString();
            var args = vector.GetProperty("args");

            switch (fn)
            {
                case "compareVersions":
                {
                    var a = args[0].GetString()!;
                    var b = args[1].GetString()!;
                    var expected = vector.GetProperty("expected").GetInt32();
                    Assert.Equal(expected, Semver.CompareVersions(a, b));
                    break;
                }
                case "satisfiesKernel":
                {
                    var kernelVersion = args[0].GetString()!;
                    var minKernelVersion = AsNullableString(args[1]);
                    var expected = vector.GetProperty("expected").GetBoolean();
                    Assert.Equal(expected, Semver.SatisfiesKernel(kernelVersion, minKernelVersion));
                    break;
                }
                case "satisfiesModRange":
                {
                    var modVersion = AsNullableString(args[0]);
                    var range = AsVersionRange(args[1]);
                    var expected = vector.GetProperty("expected").GetBoolean();
                    Assert.Equal(expected, Semver.SatisfiesModRange(modVersion, range));
                    break;
                }
                default:
                    throw new InvalidOperationException($"Unknown golden-fixture fn: {fn}");
            }
        }

        private static string? AsNullableString(JsonElement element) =>
            element.ValueKind == JsonValueKind.Null ? null : element.GetString();

        private static VersionRange? AsVersionRange(JsonElement element)
        {
            if (element.ValueKind == JsonValueKind.Null) return null;

            return new VersionRange
            {
                Min = element.GetProperty("min").GetString()!,
                Max = element.TryGetProperty("max", out var maxElement)
                    ? AsNullableString(maxElement)
                    : null,
            };
        }
    }
}
